/**
 * Smoke-check the built live-editing.js bundle against the expectations
 * documented in this fixture's README. Run after `npm run build`.
 *
 * Each assertion is a substring match — the bundle is generated by esbuild
 * from a string template, so the literals we emit (e.g. `registerProcessEnv(`,
 * `registerEleventyData(`) survive bundling verbatim.
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const here = path.dirname(fileURLToPath(import.meta.url));
const bundlePath = path.join(here, "_site", "live-editing.js");

if (!fs.existsSync(bundlePath)) {
  console.error(`Bundle not found at ${bundlePath}. Run \`npm run build\` first.`);
  process.exit(1);
}

const bundle = fs.readFileSync(bundlePath, "utf8");

/** @type {Array<{name: string, match: string | RegExp}>} */
const expectations = [
  // Engine + builtins wiring
  { name: "createSharedLiquidEngine call", match: "createSharedLiquidEngine(" },
  { name: "registerEleventyBuiltins call", match: "registerEleventyBuiltins(" },

  // Auto-mirrored filters / shortcodes from eleventy.config.mjs
  { name: "auto-mirrored filter `shout`", match: 'registerFilter("shout"' },
  { name: "auto-mirrored shortcode `year`", match: 'registerShortcode("year"' },
  { name: "auto-mirrored paired shortcode `highlight`", match: 'registerPairedShortcode("highlight"' },

  // Browser overrides
  { name: "override filter `currentPageUrl`", match: 'registerFilter("currentPageUrl"' },
  { name: "custom tag `echo`", match: 'registerCustomTag("echo"' },
  { name: "component `card`", match: 'registerLiquidComponent("card"' },

  // Env allowlist + prefix
  { name: "registerProcessEnv call", match: /registerProcessEnv\(\{[^)]*"NODE_ENV"/ },
  { name: "env includes a PUBLIC_-prefixed var", match: /registerProcessEnv\(\{[^)]*"PUBLIC_/ },

  // Static eleventy global
  { name: "registerEleventyData call", match: "registerEleventyData(" },
  { name: "eleventyData has version", match: /registerEleventyData\(\{[^)]*"version"/ },
  { name: "eleventyData has directories", match: /registerEleventyData\(\{[^)]*"directories"/ },
  { name: "eleventy.env.runMode is 'serve'", match: '"runMode":"serve"' },

  // In-memory liquid files
  { name: "window.cc_liquid_files init", match: "window.cc_liquid_files" },
  { name: "card.liquid registered into cc_liquid_files", match: "card.liquid" },
];

let failures = 0;
for (const { name, match } of expectations) {
  const ok = typeof match === "string" ? bundle.includes(match) : match.test(bundle);
  if (ok) {
    console.log(`  ok  ${name}`);
  } else {
    failures++;
    console.error(`  FAIL ${name} (expected match: ${match})`);
  }
}

if (failures > 0) {
  console.error(`\n${failures} bundle expectation(s) not met.`);
  process.exit(1);
}
console.log(`\nAll ${expectations.length} bundle expectations met.`);
